    tags: [STANDARD_TAGS.TRICKY, STANDARD_TAGS.CONCEPTUAL, STANDARD_TAGS.BEYOND_NCERT, STANDARD_TAGS.PROCESS_BASED, "class9", "ch01", "hots", "plasmolysis", "tonoplast", "plasma-membrane"],
